SELECT count(*) FROM name, aka_name, cast_info, title, movie_info, kind_type, movie_companies, movie_keyword WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id;